+/**
+ * Analytics dashboard route handlers.
+ *
+ * This module defines the API surface for the analytics feature.
+ * Each handler is a thin adapter: it parses request parameters,
+ * calls the AnalyticsService, and returns the response.
+ *
+ * Route structure:
+ *   GET /api/analytics/dashboard       — Full dashboard with all metrics
+ *   GET /api/analytics/metrics/:type   — Single metric detail (revenue|orders|users|conversion)
+ *   GET /api/analytics/orders/status   — Order status breakdown
+ *   GET /api/analytics/users/top       — Top users by revenue
+ *
+ * All routes accept these common query parameters:
+ *   - start: ISO 8601 date string (required)
+ *   - end:   ISO 8601 date string (required)
+ *   - granularity: hour|day|week|month (default: "day")
+ *
+ * Architecture note:
+ * Since this codebase doesn't use an HTTP framework yet, these handlers
+ * are framework-agnostic functions that accept a typed request and return
+ * a typed response. When an HTTP layer is added (Express, Fastify, etc.),
+ * wrap these handlers in the framework's route registration.
+ */
+
+import type { AnalyticsService } from '../services/analytics.service.js';
+import type {
+  AnalyticsQuery,
+  DashboardData,
+  MetricDetailResponse,
+  MetricType,
+  OrderStatusResponse,
+  TimeGranularity,
+  TopUsersResponse,
+} from '../models/analytics.js';
+
+// ---------------------------------------------------------------------------
+// Request / Response types for the route layer
+// ---------------------------------------------------------------------------
+
+/**
+ * Common query string parameters shared by all analytics endpoints.
+ */
+export interface AnalyticsRequestParams {
+  /** ISO 8601 start date */
+  start: string;
+  /** ISO 8601 end date */
+  end: string;
+  /** Time bucket granularity (default: "day") */
+  granularity?: string;
+}
+
+/**
+ * Parameters specific to the metric detail endpoint.
+ */
+export interface MetricDetailParams extends AnalyticsRequestParams {
+  /** The metric type from the URL path */
+  type: string;
+}
+
+/**
+ * Parameters specific to the top users endpoint.
+ */
+export interface TopUsersParams extends AnalyticsRequestParams {
+  /** Maximum number of users to return (default: 10) */
+  limit?: string;
+}
+
+// ---------------------------------------------------------------------------
+// Parsing and validation helpers
+// ---------------------------------------------------------------------------
+
+const VALID_METRIC_TYPES: MetricType[] = [
+  'revenue',
+  'orders',
+  'users',
+  'conversion',
+];
+
+const VALID_GRANULARITIES: TimeGranularity[] = [
+  'hour',
+  'day',
+  'week',
+  'month',
+];
+
+/**
+ * Parse common analytics query parameters into a typed AnalyticsQuery.
+ * Throws on invalid input so callers can return 400 responses.
+ */
+export function parseAnalyticsQuery(params: AnalyticsRequestParams): AnalyticsQuery {
+  const start = new Date(params.start);
+  const end = new Date(params.end);
+
+  if (isNaN(start.getTime())) {
+    throw new Error(`Invalid start date: ${params.start}`);
+  }
+  if (isNaN(end.getTime())) {
+    throw new Error(`Invalid end date: ${params.end}`);
+  }
+  if (start > end) {
+    throw new Error('Start date must be before end date');
+  }
+
+  const granularity = (params.granularity ?? 'day') as TimeGranularity;
+  if (!VALID_GRANULARITIES.includes(granularity)) {
+    throw new Error(
+      `Invalid granularity: ${params.granularity}. Must be one of: ${VALID_GRANULARITIES.join(', ')}`,
+    );
+  }
+
+  return {
+    timeRange: { start, end },
+    granularity,
+  };
+}
+
+/**
+ * Validate that a string is a valid MetricType.
+ */
+export function parseMetricType(type: string): MetricType {
+  if (!VALID_METRIC_TYPES.includes(type as MetricType)) {
+    throw new Error(
+      `Invalid metric type: ${type}. Must be one of: ${VALID_METRIC_TYPES.join(', ')}`,
+    );
+  }
+  return type as MetricType;
+}
+
+// ---------------------------------------------------------------------------
+// Route handler class
+// ---------------------------------------------------------------------------
+
+/**
+ * Analytics route handlers. Each method corresponds to one API endpoint.
+ *
+ * Usage (when wiring up an HTTP framework):
+ * ```ts
+ * const handler = new AnalyticsRouteHandler(analyticsService);
+ * app.get('/api/analytics/dashboard', (req, res) => {
+ *   const data = await handler.getDashboard(req.query);
+ *   res.json(data);
+ * });
+ * ```
+ */
+export class AnalyticsRouteHandler {
+  constructor(private analyticsService: AnalyticsService) {}
+
+  /**
+   * GET /api/analytics/dashboard
+   *
+   * Returns the full dashboard dataset: all metric summaries,
+   * order status breakdown, and top users.
+   */
+  async getDashboard(params: AnalyticsRequestParams): Promise<DashboardData> {
+    const query = parseAnalyticsQuery(params);
+    return this.analyticsService.getDashboard(query);
+  }
+
+  /**
+   * GET /api/analytics/metrics/:type
+   *
+   * Returns detailed data for a single metric.
+   * :type must be one of: revenue, orders, users, conversion
+   */
+  async getMetricDetail(
+    params: MetricDetailParams,
+  ): Promise<MetricDetailResponse> {
+    const query = parseAnalyticsQuery(params);
+    const metricType = parseMetricType(params.type);
+    return this.analyticsService.getMetricDetail(metricType, query);
+  }
+
+  /**
+   * GET /api/analytics/orders/status
+   *
+   * Returns the order status breakdown for the given time range.
+   */
+  async getOrderStatusBreakdown(
+    params: AnalyticsRequestParams,
+  ): Promise<OrderStatusResponse> {
+    const query = parseAnalyticsQuery(params);
+    return this.analyticsService.getOrderStatusBreakdown(query);
+  }
+
+  /**
+   * GET /api/analytics/users/top
+   *
+   * Returns the top users by revenue for the given time range.
+   */
+  async getTopUsers(params: TopUsersParams): Promise<TopUsersResponse> {
+    const query = parseAnalyticsQuery(params);
+    const limit = params.limit ? parseInt(params.limit, 10) : undefined;
+
+    if (limit !== undefined && (isNaN(limit) || limit < 1)) {
+      throw new Error(`Invalid limit: ${params.limit}. Must be a positive integer`);
+    }
+
+    return this.analyticsService.getTopUsers(query, limit);
+  }
+}

